svg.script:
var seed = 200;
function rand() { seed = (seed * 16807 + 0) % 2147483647; return (seed - 1) / 2147483646; }
function noise() { return (rand() - 0.5) * 2; }

var W = 720, H = 230, OX = 50, OY = 20;
var midY = OY + H / 2;
var totalTime = 60;
var samplesPerSec = 20; // lower sample rate for 60s to keep path manageable
var totalSamples = totalTime * samplesPerSec;

// 6-min walk: sustained walking with a turn around 26-28s
// Subtle fatigue: amplitude decreases ~8% over 60s
function getTurnFactor(t) {
  // Turn at 26-28s: amplitude dip + irregular
  if (t >= 26 && t <= 28) {
    var f = (t - 26) / 2.0;
    var dip = 1.0 - 0.5 * Math.sin(f * Math.PI);
    return dip;
  }
  return 1.0;
}

function getFatigue(t) {
  // Subtle decrease: 1.0 at t=0, 0.92 at t=60
  return 1.0 - 0.08 * (t / totalTime);
}

function isTurn(t) {
  return t >= 26 && t <= 28;
}

function genSignal(ampWalk, freqWalk, phaseOff, noiseScale) {
  var pts = [];
  for (var i = 0; i < totalSamples; i++) {
    var t = i / samplesPerSec;
    var turn = getTurnFactor(t);
    var fatigue = getFatigue(t);
    var amp = ampWalk * turn * fatigue;

    var val;
    if (isTurn(t)) {
      // Irregular pattern during turn
      val = amp * (
        Math.sin(2 * Math.PI * 1.1 * t + phaseOff) * 0.4 +
        Math.sin(2 * Math.PI * 2.5 * t + phaseOff * 2.3) * 0.3 +
        Math.sin(2 * Math.PI * 0.7 * t + phaseOff * 0.5) * 0.3
      ) + noise() * noiseScale * 1.8;
    } else {
      // Regular walking rhythm
      val = amp * (
        Math.sin(2 * Math.PI * freqWalk * t + phaseOff) * 0.65 +
        Math.sin(2 * Math.PI * freqWalk * 2 * t + phaseOff * 0.8) * 0.2 +
        Math.sin(2 * Math.PI * freqWalk * 3 * t + phaseOff * 1.5) * 0.08 +
        Math.sin(2 * Math.PI * freqWalk * 0.5 * t + phaseOff * 1.9) * 0.07
      ) + noise() * noiseScale;
    }
    pts.push(val);
  }
  return pts;
}

var xSig = genSignal(0.20, 1.6, 0, 0.016);
var ySig = genSignal(0.13, 1.6, 1.7, 0.012);
var zSig = genSignal(0.18, 1.6, 3.4, 0.014);

function toPath(sig) {
  var maxAmp = 0.30;
  var d = "";
  for (var i = 0; i < sig.length; i++) {
    var x = OX + (i / totalSamples) * W;
    var y = midY - (sig[i] / maxAmp) * (H / 2 - 10);
    d += (i === 0 ? "M" : "L") + x.toFixed(1) + "," + y.toFixed(1);
  }
  return d;
}

document.getElementById("pathX").setAttribute("d", toPath(xSig));
document.getElementById("pathY").setAttribute("d", toPath(ySig));
document.getElementById("pathZ").setAttribute("d", toPath(zSig));
